@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun TaskEditScreen(
    todoId: String,
    taskId: String?,
    navController: NavHostController,
    viewModel: TaskEditViewModel = hiltViewModel(),
) {
    val form by viewModel.form.collectAsStateWithLifecycle()
    val dateFmt = SimpleDateFormat("MMM d, yyyy", Locale.getDefault())
    val timeFmt = SimpleDateFormat("HH:mm", Locale.getDefault())

    // Navigate back when saved
    LaunchedEffect(form.isSaved) {
        if (form.isSaved) navController.popBackStack()
    }

    var showDueDatePicker by remember { mutableStateOf(false) }
    var showStartTimePicker by remember { mutableStateOf(false) }
    var showReminderPicker by remember { mutableStateOf(false) }
    var statusExpanded by remember { mutableStateOf(false) }

    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text(if (taskId == null) "New Task" else "Edit Task") },
                navigationIcon = {
                    IconButton(onClick = { navController.popBackStack() }) {
                        Icon(Icons.AutoMirrored.Filled.ArrowBack, contentDescription = "Back")
                    }
                }
            )
        },
        floatingActionButton = {
            FloatingActionButton(
                onClick = { viewModel.save() },
                content = { Icon(Icons.Default.Check, contentDescription = "Save") }
            )
        }
    ) { padding ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(padding)
                .padding(16.dp)
                .verticalScroll(rememberScrollState()),
            verticalArrangement = Arrangement.spacedBy(12.dp),
        ) {
            // Title
            OutlinedTextField(
                value = form.title,
                onValueChange = viewModel::onTitleChange,
                label = { Text("Title *") },
                isError = form.error != null,
                supportingText = form.error?.let { { Text(it, color = MaterialTheme.colorScheme.error) } },
                modifier = Modifier.fillMaxWidth(),
                singleLine = true,
            )

            // Status
            ExposedDropdownMenuBox(
                expanded = statusExpanded,
                onExpandedChange = { statusExpanded = it },
            ) {
                OutlinedTextField(
                    value = form.status.name.replace('_', ' '),
                    onValueChange = {},
                    readOnly = true,
                    label = { Text("Status") },
                    trailingIcon = { ExposedDropdownMenuDefaults.TrailingIcon(statusExpanded) },
                    modifier = Modifier.fillMaxWidth().menuAnchor(androidx.compose.material3.MenuAnchorType.PrimaryNotEditable),
                )
                ExposedDropdownMenu(expanded = statusExpanded, onDismissRequest = { statusExpanded = false }) {
                    TaskStatus.entries.forEach { status ->
                        DropdownMenuItem(
                            text = { Text(status.name.replace('_', ' ')) },
                            onClick = { viewModel.onStatusChange(status); statusExpanded = false },
                        )
                    }
                }
            }

            // Priority
            Text("Priority", style = MaterialTheme.typography.labelMedium)
            Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                listOf(1 to "Critical", 2 to "High", 3 to "Medium", 4 to "Low").forEach { (value, label) ->
                    FilterChip(
                        selected = form.priority == value,
                        onClick = { viewModel.onPriorityChange(value) },
                        label = { Text(label) },
                    )
                }
            }

            // Due date
            Text("Due Date", style = MaterialTheme.typography.labelMedium)
            Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                OutlinedTextField(
                    value = dateFmt.format(Date(form.dueDate)),
                    onValueChange = {},
                    readOnly = true,
                    modifier = Modifier.weight(1f),
                    label = { Text("Date") },
                )
                TextButton(onClick = { showDueDatePicker = true }) { Text("Pick") }
            }

            // Start time (optional)
            Text("Start Time (optional)", style = MaterialTheme.typography.labelMedium)
            Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                OutlinedTextField(
                    value = form.startTime?.let { timeFmt.format(Date(it)) } ?: "—",
                    onValueChange = {},
                    readOnly = true,
                    modifier = Modifier.weight(1f),
                    label = { Text("Time") },
                )
                TextButton(onClick = { showStartTimePicker = true }) { Text("Pick") }
                if (form.startTime != null) {
                    TextButton(onClick = { viewModel.onStartTimeChange(null) }) { Text("Clear") }
                }
            }

            // ── Reminder time ────────────────────────────────────────────────────
            Text("Reminder (optional)", style = MaterialTheme.typography.labelMedium)
            Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                OutlinedTextField(
                    value = form.reminderAt?.let { timeFmt.format(Date(it)) } ?: "—",
                    onValueChange = {},
                    readOnly = true,
                    modifier = Modifier.weight(1f),
                    label = { Text("Reminder time") },
                )
                TextButton(onClick = { showReminderPicker = true }) { Text("Pick") }
                if (form.reminderAt != null) {
                    TextButton(onClick = { viewModel.onReminderChange(null) }) { Text("Clear") }
                }
            }

            // ── Location trigger ─────────────────────────────────────────────────
            HorizontalDivider(Modifier.padding(vertical = 4.dp))
            Row(
                modifier = Modifier.fillMaxWidth(),
                verticalAlignment = Alignment.CenterVertically,
            ) {
                Column(Modifier.weight(1f)) {
                    Text("Location trigger", style = MaterialTheme.typography.labelLarge)
                    Text(
                        "Get notified when near this location",
                        style = MaterialTheme.typography.bodySmall,
                        color = MaterialTheme.colorScheme.onSurfaceVariant,
                    )
                }
                Switch(
                    checked = form.locationEnabled,
                    onCheckedChange = viewModel::onLocationToggle,
                )
            }

            if (form.locationEnabled) {
                OutlinedTextField(
                    value = form.locationLabel,
                    onValueChange = viewModel::onLocationLabelChange,
                    label = { Text("Location label (optional)") },
                    modifier = Modifier.fillMaxWidth(),
                    singleLine = true,
                )
                Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                    OutlinedTextField(
                        value = form.locationLat,
                        onValueChange = viewModel::onLocationLatChange,
                        label = { Text("Latitude") },
                        modifier = Modifier.weight(1f),
                        singleLine = true,
                        keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Decimal),
                        isError = form.locationLat.isNotBlank() && form.locationLat.toDoubleOrNull() == null,
                    )
                    OutlinedTextField(
                        value = form.locationLng,
                        onValueChange = viewModel::onLocationLngChange,
                        label = { Text("Longitude") },
                        modifier = Modifier.weight(1f),
                        singleLine = true,
                        keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Decimal),
                        isError = form.locationLng.isNotBlank() && form.locationLng.toDoubleOrNull() == null,
                    )
                }
                Text(
                    "Radius: ${form.locationRadius.toInt()} m",
                    style = MaterialTheme.typography.labelMedium,
                )
                Slider(
                    value = form.locationRadius,
                    onValueChange = viewModel::onLocationRadiusChange,
                    valueRange = 100f..5000f,
                    steps = 49, // steps of ~100m
                    modifier = Modifier.fillMaxWidth(),
                )
            }

            Spacer(Modifier.height(72.dp)) // FAB clearance
        }
    }

    // Date picker modal
    if (showDueDatePicker) {
        DatePickerModal(
            initialDateMs = form.dueDate,
            onDateSelected = { viewModel.onDueDateChange(it); showDueDatePicker = false },
            onDismiss = { showDueDatePicker = false },
        )
    }

    // Start time picker modal
    if (showStartTimePicker) {
        val cal = Calendar.getInstance().apply { timeInMillis = form.startTime ?: form.dueDate }
        TimePickerModal(
            initialHour = cal.get(Calendar.HOUR_OF_DAY),
            initialMinute = cal.get(Calendar.MINUTE),
            onTimeSelected = { h, m ->
                val base = Calendar.getInstance().apply { timeInMillis = form.dueDate }
                base.set(Calendar.HOUR_OF_DAY, h); base.set(Calendar.MINUTE, m); base.set(Calendar.SECOND, 0)
                viewModel.onStartTimeChange(base.timeInMillis)
                showStartTimePicker = false
            },
            onDismiss = { showStartTimePicker = false },
        )
    }

    // Reminder time picker modal
    if (showReminderPicker) {
        val cal = Calendar.getInstance().apply { timeInMillis = form.reminderAt ?: form.dueDate }
        TimePickerModal(
            initialHour = cal.get(Calendar.HOUR_OF_DAY),
            initialMinute = cal.get(Calendar.MINUTE),
            onTimeSelected = { h, m ->
                val base = Calendar.getInstance().apply { timeInMillis = form.dueDate }
                base.set(Calendar.HOUR_OF_DAY, h); base.set(Calendar.MINUTE, m); base.set(Calendar.SECOND, 0)
                viewModel.onReminderChange(base.timeInMillis)
                showReminderPicker = false
            },
            onDismiss = { showReminderPicker = false },
        )
    }
}

package com.example.todoit.presentation.tasks

import androidx.lifecycle.SavedStateHandle
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.example.todoit.domain.model.Task
import com.example.todoit.domain.model.TaskStatus
import com.example.todoit.domain.repository.TaskRepository
import com.example.todoit.domain.usecase.task.UpsertTaskUseCase
import dagger.hilt.android.lifecycle.HiltViewModel
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.update
import kotlinx.coroutines.launch
import java.util.UUID
import javax.inject.Inject

data class TaskEditFormState(
    val id: String = "",
    val todoId: String = "",
    val title: String = "",
    val status: TaskStatus = TaskStatus.PENDING,
    val priority: Int = 3,
    val dueDate: Long = System.currentTimeMillis(),
    val startTime: Long? = null,
    val reminderAt: Long? = null,
    val inheritSchedule: Boolean = true,
    /** 0L = new task (UpsertTaskUseCase will assign createdAt); non-zero = original task timestamp. */
    val originalCreatedAt: Long = 0L,
    val isSaving: Boolean = false,
    val isSaved: Boolean = false,
    val error: String? = null,
)

@HiltViewModel
class TaskEditViewModel @Inject constructor(
    savedStateHandle: SavedStateHandle,
    private val taskRepository: TaskRepository,
    private val upsertTask: UpsertTaskUseCase,
) : ViewModel() {

    private val taskId: String? = savedStateHandle["taskId"]
    private val todoId: String = checkNotNull(savedStateHandle["todoId"])

    private val _form = MutableStateFlow(TaskEditFormState(todoId = todoId))
    val form: StateFlow<TaskEditFormState> = _form.asStateFlow()

    init {
        if (!taskId.isNullOrBlank()) {
            viewModelScope.launch {
                val task = taskRepository.getTaskById(taskId)
                if (task != null) {
                    _form.update {
                        it.copy(
                            id = task.id,
                            todoId = task.todoId,
                            title = task.title,
                            status = task.status,
                            priority = task.priority,
                            dueDate = task.dueDate,
                            startTime = task.startTime,
                            reminderAt = task.reminderAt,
                            inheritSchedule = task.inheritSchedule,
                            originalCreatedAt = task.createdAt,
                        )
                    }
                }
            }
        }
    }

    fun onTitleChange(v: String) = _form.update { it.copy(title = v, error = null) }
    fun onStatusChange(v: TaskStatus) = _form.update { it.copy(status = v) }
    fun onPriorityChange(v: Int) = _form.update { it.copy(priority = v) }
    fun onDueDateChange(v: Long) = _form.update { it.copy(dueDate = v) }
    fun onStartTimeChange(v: Long?) = _form.update { it.copy(startTime = v) }
    fun onReminderChange(v: Long?) = _form.update { it.copy(reminderAt = v) }

    fun save() {
        val f = _form.value
        if (f.title.isBlank()) {
            _form.update { it.copy(error = "Title is required") }
            return
        }
        _form.update { it.copy(isSaving = true, error = null) }
        viewModelScope.launch {
            runCatching {
                upsertTask(
                    Task(
                        id = f.id.ifBlank { UUID.randomUUID().toString() },
                        todoId = f.todoId,
                        title = f.title.trim(),
                        status = f.status,
                        priority = f.priority,
                        dueDate = f.dueDate,
                        startTime = f.startTime,
                        reminderAt = f.reminderAt,
                        locationId = null,
                        scheduleId = null,
                        inheritSchedule = f.inheritSchedule,
                        recurrenceId = null,
                        recurrenceInstanceDate = null,
                        parentTaskId = null,
                        scoreCache = 0f,
                        createdAt = f.originalCreatedAt, // 0L for new tasks → UpsertTaskUseCase sets now
                        updatedAt = System.currentTimeMillis(),
                        deletedAt = null,
                    )
                )
            }.onSuccess {
                _form.update { it.copy(isSaving = false, isSaved = true) }
            }.onFailure { e ->
                _form.update { it.copy(isSaving = false, error = e.message) }
            }
        }
    }
}

package com.example.todoit.presentation.tasks

import androidx.lifecycle.SavedStateHandle
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.example.todoit.domain.model.Location
import com.example.todoit.domain.model.Task
import com.example.todoit.domain.model.TaskStatus
import com.example.todoit.domain.repository.LocationRepository
import com.example.todoit.domain.repository.TaskRepository
import com.example.todoit.domain.usecase.task.UpsertTaskUseCase
import dagger.hilt.android.lifecycle.HiltViewModel
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.update
import kotlinx.coroutines.launch
import java.util.UUID
import javax.inject.Inject

data class TaskEditFormState(
    val id: String = "",
    val todoId: String = "",
    val title: String = "",
    val status: TaskStatus = TaskStatus.PENDING,
    val priority: Int = 3,
    val dueDate: Long = System.currentTimeMillis(),
    val startTime: Long? = null,
    val reminderAt: Long? = null,
    val inheritSchedule: Boolean = true,
    /** 0L = new task (UpsertTaskUseCase will assign createdAt); non-zero = original task timestamp. */
    val originalCreatedAt: Long = 0L,
    // ── Location ───────────────────────────────────────────────────────────────
    /** true when user has toggled "Enable location trigger" */
    val locationEnabled: Boolean = false,
    /** existing location id when editing a task that already has one */
    val locationId: String? = null,
    val locationLabel: String = "",
    val locationLat: String = "",
    val locationLng: String = "",
    /** Geofence radius in metres (100–5000) */
    val locationRadius: Float = 300f,
    // ── Save state ─────────────────────────────────────────────────────────────
    val isSaving: Boolean = false,
    val isSaved: Boolean = false,
    val error: String? = null,
)

@HiltViewModel
class TaskEditViewModel @Inject constructor(
    savedStateHandle: SavedStateHandle,
    private val taskRepository: TaskRepository,
    private val locationRepository: LocationRepository,
    private val upsertTask: UpsertTaskUseCase,
) : ViewModel() {

    private val taskId: String? = savedStateHandle["taskId"]
    private val todoId: String = checkNotNull(savedStateHandle["todoId"])

    private val _form = MutableStateFlow(TaskEditFormState(todoId = todoId))
    val form: StateFlow<TaskEditFormState> = _form.asStateFlow()

    init {
        if (!taskId.isNullOrBlank()) {
            viewModelScope.launch {
                val task = taskRepository.getTaskById(taskId)
                if (task != null) {
                    // Load any linked location
                    val loc = task.locationId?.let { locationRepository.getLocationById(it) }
                    _form.update {
                        it.copy(
                            id = task.id,
                            todoId = task.todoId,
                            title = task.title,
                            status = task.status,
                            priority = task.priority,
                            dueDate = task.dueDate,
                            startTime = task.startTime,
                            reminderAt = task.reminderAt,
                            inheritSchedule = task.inheritSchedule,
                            originalCreatedAt = task.createdAt,
                            locationEnabled = loc != null,
                            locationId = loc?.id,
                            locationLabel = loc?.label ?: "",
                            locationLat = loc?.latitude?.toString() ?: "",
                            locationLng = loc?.longitude?.toString() ?: "",
                            locationRadius = loc?.radiusMeters ?: 300f,
                        )
                    }
                }
            }
        }
    }

    // ── Form handlers ─────────────────────────────────────────────────────────
    fun onTitleChange(v: String) = _form.update { it.copy(title = v, error = null) }
    fun onStatusChange(v: TaskStatus) = _form.update { it.copy(status = v) }
    fun onPriorityChange(v: Int) = _form.update { it.copy(priority = v) }
    fun onDueDateChange(v: Long) = _form.update { it.copy(dueDate = v) }
    fun onStartTimeChange(v: Long?) = _form.update { it.copy(startTime = v) }
    fun onReminderChange(v: Long?) = _form.update { it.copy(reminderAt = v) }

    fun onLocationToggle(enabled: Boolean) = _form.update { it.copy(locationEnabled = enabled) }
    fun onLocationLabelChange(v: String) = _form.update { it.copy(locationLabel = v) }
    fun onLocationLatChange(v: String) = _form.update { it.copy(locationLat = v) }
    fun onLocationLngChange(v: String) = _form.update { it.copy(locationLng = v) }
    fun onLocationRadiusChange(v: Float) = _form.update { it.copy(locationRadius = v) }

    // ── Save ─────────────────────────────────────────────────────────────────
    fun save() {
        val f = _form.value
        if (f.title.isBlank()) {
            _form.update { it.copy(error = "Title is required") }
            return
        }
        if (f.locationEnabled) {
            val lat = f.locationLat.toDoubleOrNull()
            val lng = f.locationLng.toDoubleOrNull()
            if (lat == null || lng == null || lat !in -90.0..90.0 || lng !in -180.0..180.0) {
                _form.update { it.copy(error = "Invalid location coordinates") }
                return
            }
        }
        _form.update { it.copy(isSaving = true, error = null) }
        viewModelScope.launch {
            runCatching {
                val resolvedLocationId: String? = if (f.locationEnabled) {
                    val lat = f.locationLat.toDouble()
                    val lng = f.locationLng.toDouble()
                    val locId = f.locationId ?: UUID.randomUUID().toString()
                    locationRepository.upsertLocation(
                        Location(
                            id = locId,
                            label = f.locationLabel.ifBlank { "Task location" },
                            latitude = lat,
                            longitude = lng,
                            radiusMeters = f.locationRadius,
                            updatedAt = System.currentTimeMillis(),
                            deletedAt = null,
                        )
                    )
                    locId
                } else {
                    // If location was disabled on an existing task, soft-delete the old location
                    if (f.locationId != null) locationRepository.softDeleteLocation(f.locationId)
                    null
                }

                upsertTask(
                    Task(
                        id = f.id.ifBlank { UUID.randomUUID().toString() },
                        todoId = f.todoId,
                        title = f.title.trim(),
                        status = f.status,
                        priority = f.priority,
                        dueDate = f.dueDate,
                        startTime = f.startTime,
                        reminderAt = f.reminderAt,
                        locationId = resolvedLocationId,
                        scheduleId = null,
                        inheritSchedule = f.inheritSchedule,
                        recurrenceId = null,
                        recurrenceInstanceDate = null,
                        parentTaskId = null,
                        scoreCache = 0f,
                        createdAt = f.originalCreatedAt,
                        updatedAt = System.currentTimeMillis(),
                        deletedAt = null,
                    )
                )
            }.onSuccess {
                _form.update { it.copy(isSaving = false, isSaved = true) }
            }.onFailure { e ->
                _form.update { it.copy(isSaving = false, error = e.message) }
            }
        }
    }
}

package com.example.todoit.domain.engine

import com.example.todoit.domain.model.Recurrence
import com.example.todoit.domain.model.RecurrenceType
import com.example.todoit.domain.model.Task
import com.example.todoit.domain.model.TaskStatus
import org.junit.Assert.assertEquals
import org.junit.Assert.assertTrue
import org.junit.Before
import org.junit.Test
import java.util.Calendar

class RecurrenceExpanderTest {

    private lateinit var expander: RecurrenceExpander

    // Anchor: 2025-01-06 09:00 (Monday)
    private val MONDAY_9AM: Long = run {
        val cal = Calendar.getInstance()
        cal.set(2025, Calendar.JANUARY, 6, 9, 0, 0)
        cal.set(Calendar.MILLISECOND, 0)
        cal.timeInMillis
    }

    @Before
    fun setUp() {
        expander = RecurrenceExpander()
    }

    private fun baseTask(dueDate: Long = MONDAY_9AM) = Task(
        id = "root", todoId = "todo1", title = "Root",
        status = TaskStatus.PENDING, priority = 2,
        dueDate = dueDate, startTime = null, reminderAt = null,
        locationId = null, scheduleId = null, inheritSchedule = false,
        recurrenceId = "rec1", recurrenceInstanceDate = null, parentTaskId = null,
        scoreCache = 0f, createdAt = MONDAY_9AM, updatedAt = MONDAY_9AM, deletedAt = null,
    )

    private fun recurrence(
        type: RecurrenceType = RecurrenceType.DAILY,
        interval: Int = 1,
        daysOfWeek: List<Int>? = null,
        endDate: Long? = null,
        maxOccurrences: Int? = null,
    ) = Recurrence("rec1", type, interval, daysOfWeek, endDate, maxOccurrences, MONDAY_9AM)

    // ── DAILY ─────────────────────────────────────────────────────────────────

    @Test
    fun `daily recurrence generates correct number of instances within window`() {
        val from = MONDAY_9AM
        val upTo = MONDAY_9AM + 7L * 24 * 3_600_000 // 7 days ahead
        val instances = expander.expand(baseTask(), recurrence(type = RecurrenceType.DAILY, interval = 1), from, upTo)
        // 7 days ahead: instances at day+1, +2, +3, +4, +5, +6, +7
        assertEquals(7, instances.size)
    }

    @Test
    fun `daily recurrence instances all have parentTaskId set`() {
        val from = MONDAY_9AM
        val upTo = MONDAY_9AM + 3L * 24 * 3_600_000
        val instances = expander.expand(baseTask(), recurrence(type = RecurrenceType.DAILY, interval = 1), from, upTo)
        assertTrue(instances.all { it.parentTaskId == "root" })
    }

    @Test
    fun `daily recurrence instances all have PENDING status`() {
        val from = MONDAY_9AM
        val upTo = MONDAY_9AM + 3L * 24 * 3_600_000
        val instances = expander.expand(baseTask(), recurrence(type = RecurrenceType.DAILY, interval = 1), from, upTo)
        assertTrue(instances.all { it.status == TaskStatus.PENDING })
    }

    @Test
    fun `daily recurrence every 2 days generates correct instances`() {
        val from = MONDAY_9AM
        val upTo = MONDAY_9AM + 14L * 24 * 3_600_000 // 14 days
        val instances = expander.expand(baseTask(), recurrence(type = RecurrenceType.DAILY, interval = 2), from, upTo)
        // days 2, 4, 6, 8, 10, 12, 14 → 7 instances
        assertEquals(7, instances.size)
    }

    @Test
    fun `maxOccurrences caps instance count`() {
        val from = MONDAY_9AM
        val upTo = MONDAY_9AM + 90L * 24 * 3_600_000
        val instances = expander.expand(
            baseTask(),
            recurrence(type = RecurrenceType.DAILY, interval = 1, maxOccurrences = 5),
            from, upTo,
        )
        assertEquals(5, instances.size)
    }

    @Test
    fun `endDate caps instance generation`() {
        val endDate = MONDAY_9AM + 4L * 24 * 3_600_000 // 4 days later
        val from = MONDAY_9AM
        val upTo = MONDAY_9AM + 30L * 24 * 3_600_000
        val instances = expander.expand(
            baseTask(),
            recurrence(type = RecurrenceType.DAILY, interval = 1, endDate = endDate),
            from, upTo,
        )
        // instances at day+1, +2, +3, +4 = 4 instances
        assertEquals(4, instances.size)
    }

    @Test
    fun `instances have unique IDs`() {
        val from = MONDAY_9AM
        val upTo = MONDAY_9AM + 7L * 24 * 3_600_000
        val instances = expander.expand(baseTask(), recurrence(type = RecurrenceType.DAILY, interval = 1), from, upTo)
        val ids = instances.map { it.id }.toSet()
        assertEquals(instances.size, ids.size)
    }

    // ── WEEKLY ─────────────────────────────────────────────────────────────────

    @Test
    fun `weekly recurrence without daysOfWeek generates weekly instances`() {
        val from = MONDAY_9AM
        val upTo = MONDAY_9AM + 28L * 24 * 3_600_000 // 4 weeks
        val instances = expander.expand(baseTask(), recurrence(type = RecurrenceType.WEEKLY, interval = 1), from, upTo)
        // Should generate on weeks 1, 2, 3, 4 after the root
        assertEquals(4, instances.size)
    }

    @Test
    fun `weekly recurrence with specific daysOfWeek produces instances on matching days`() {
        // Root is Monday (ISO 1); daysOfWeek = [1, 3] (Mon and Wed).
        // Algorithm: advance 7 days first → next Monday, which IS in [1,3] → stays on Monday.
        // So two instances: Mon Jan 13 and Mon Jan 20 within the 14-day window.
        val from = MONDAY_9AM
        val upTo = MONDAY_9AM + 14L * 24 * 3_600_000 // 2 weeks
        val instances = expander.expand(
            baseTask(),
            recurrence(type = RecurrenceType.WEEKLY, interval = 1, daysOfWeek = listOf(1, 3)),
            from, upTo,
        )
        assertEquals(2, instances.size)
        // All generated instances must be on a day in [1, 3]
        instances.forEach { instance ->
            val cal = Calendar.getInstance().apply { timeInMillis = instance.dueDate }
            val javaDay = cal.get(Calendar.DAY_OF_WEEK)
            val appDay = if (javaDay == Calendar.SUNDAY) 7 else javaDay - 1
            assertTrue("Day $appDay not in [1,3]", appDay == 1 || appDay == 3)
        }
    }

    // ── nextOccurrence ─────────────────────────────────────────────────────────

    @Test
    fun `nextOccurrence daily adds correct days`() {
        val next = expander.nextOccurrence(MONDAY_9AM, recurrence(type = RecurrenceType.DAILY, interval = 3))
        val expected = MONDAY_9AM + 3L * 24 * 3_600_000
        assertEquals(expected, next)
    }

    @Test
    fun `nextOccurrence CUSTOM same as DAILY`() {
        val daily = expander.nextOccurrence(MONDAY_9AM, recurrence(type = RecurrenceType.DAILY, interval = 5))
        val custom = expander.nextOccurrence(MONDAY_9AM, recurrence(type = RecurrenceType.CUSTOM, interval = 5))
        assertEquals(daily, custom)
    }

    // ── Reminder/startTime offset preservation ────────────────────────────────

    @Test
    fun `reminder offset is preserved in instances`() {
        val reminderOffset = 30L * 60 * 1000 // 30 min before
        val taskWithReminder = baseTask().copy(reminderAt = MONDAY_9AM - reminderOffset)
        val from = MONDAY_9AM
        val upTo = MONDAY_9AM + 3L * 24 * 3_600_000
        val instances = expander.expand(
            taskWithReminder,
            recurrence(type = RecurrenceType.DAILY, interval = 1),
            from, upTo,
        )
        instances.forEach { instance ->
            val expectedReminder = instance.dueDate - reminderOffset
            assertEquals(expectedReminder, instance.reminderAt)
        }
    }
}

package com.example.todoit.domain.engine

import com.example.todoit.domain.model.Schedule
import com.example.todoit.domain.model.Task
import com.example.todoit.domain.model.TaskStatus
import org.junit.Assert.assertFalse
import org.junit.Assert.assertTrue
import org.junit.Before
import org.junit.Test
import java.util.Calendar

class ScheduleEvaluatorTest {

    private lateinit var evaluator: ScheduleEvaluator

    @Before
    fun setUp() {
        evaluator = ScheduleEvaluator()
    }

    // Helper that returns a Calendar for a specific day-of-week and time
    // weekday: Calendar.MONDAY .. Calendar.SUNDAY
    private fun calendarAt(weekday: Int, hourOfDay: Int, minute: Int = 0): java.time.LocalDateTime {
        // Map Calendar.MONDAY=2..SUNDAY=1 → ISO 1=Mon..7=Sun
        val isoDay = when (weekday) {
            Calendar.MONDAY    -> 1
            Calendar.TUESDAY   -> 2
            Calendar.WEDNESDAY -> 3
            Calendar.THURSDAY  -> 4
            Calendar.FRIDAY    -> 5
            Calendar.SATURDAY  -> 6
            Calendar.SUNDAY    -> 7
            else -> throw IllegalArgumentException("Bad weekday")
        }
        // Build a LocalDateTime on the given ISO day/hour/minute
        // Use 2025-01-06 (Monday) as anchor
        val monday = java.time.LocalDateTime.of(2025, 1, 6, 0, 0, 0)
        return monday.plusDays((isoDay - 1).toLong()).withHour(hourOfDay).withMinute(minute)
    }

    private fun schedule(
        activeDays: List<Int> = emptyList(),
        startMin: Int? = null,
        endMin: Int? = null,
    ) = Schedule("s1", "Test", activeDays, startMin, endMin, 0L, null)

    // ── Null schedule = always active ──────────────────────────────────────────

    @Test
    fun `null schedule is always active`() {
        val now = calendarAt(Calendar.SUNDAY, 3)
        assertTrue(evaluator.isScheduleActive(null, now))
    }

    // ── Day-of-week filtering ─────────────────────────────────────────────────

    @Test
    fun `empty activeDays means all days active`() {
        val now = calendarAt(Calendar.SATURDAY, 12)
        assertTrue(evaluator.isScheduleActive(schedule(activeDays = emptyList()), now))
    }

    @Test
    fun `current day in activeDays returns true`() {
        // Wednesday = ISO 3
        val now = calendarAt(Calendar.WEDNESDAY, 12)
        assertTrue(evaluator.isScheduleActive(schedule(activeDays = listOf(1, 3, 5)), now))
    }

    @Test
    fun `current day NOT in activeDays returns false`() {
        // Sunday = ISO 7
        val now = calendarAt(Calendar.SUNDAY, 12)
        assertFalse(evaluator.isScheduleActive(schedule(activeDays = listOf(1, 2, 3, 4, 5)), now))
    }

    // ── Time window filtering ──────────────────────────────────────────────────

    @Test
    fun `time within window returns true`() {
        val now = calendarAt(Calendar.MONDAY, 10, 30) // 10:30 → 630 min
        val sched = schedule(startMin = 9 * 60, endMin = 18 * 60) // 9:00–18:00
        assertTrue(evaluator.isScheduleActive(sched, now))
    }

    @Test
    fun `time before window returns false`() {
        val now = calendarAt(Calendar.MONDAY, 8, 0) // 08:00 → 480 min
        val sched = schedule(startMin = 9 * 60, endMin = 18 * 60)
        assertFalse(evaluator.isScheduleActive(sched, now))
    }

    @Test
    fun `time after window returns false`() {
        val now = calendarAt(Calendar.MONDAY, 19, 0) // 19:00 → 1140 min
        val sched = schedule(startMin = 9 * 60, endMin = 18 * 60)
        assertFalse(evaluator.isScheduleActive(sched, now))
    }

    @Test
    fun `time exactly at start of window returns true`() {
        val now = calendarAt(Calendar.MONDAY, 9, 0)
        val sched = schedule(startMin = 9 * 60, endMin = 18 * 60)
        assertTrue(evaluator.isScheduleActive(sched, now))
    }

    @Test
    fun `time exactly at end of window returns true`() {
        val now = calendarAt(Calendar.MONDAY, 18, 0)
        val sched = schedule(startMin = 9 * 60, endMin = 18 * 60)
        assertTrue(evaluator.isScheduleActive(sched, now))
    }

    @Test
    fun `only startMin set without endMin means no time filter`() {
        // When only one of the two is set, the time filter should be skipped
        val now = calendarAt(Calendar.MONDAY, 7, 0)
        val sched = schedule(startMin = 9 * 60, endMin = null)
        assertTrue(evaluator.isScheduleActive(sched, now))
    }

    // ── Combined day + time ────────────────────────────────────────────────────

    @Test
    fun `active day but outside time window returns false`() {
        // Monday in activeDays, but time before window
        val now = calendarAt(Calendar.MONDAY, 7, 0)
        val sched = schedule(activeDays = listOf(1), startMin = 9 * 60, endMin = 18 * 60)
        assertFalse(evaluator.isScheduleActive(sched, now))
    }

    @Test
    fun `active day and within time window returns true`() {
        val now = calendarAt(Calendar.MONDAY, 10, 0)
        val sched = schedule(activeDays = listOf(1), startMin = 9 * 60, endMin = 18 * 60)
        assertTrue(evaluator.isScheduleActive(sched, now))
    }

    @Test
    fun `inactive day even if within time window returns false`() {
        // Sunday not in Mon-Fri schedule
        val now = calendarAt(Calendar.SUNDAY, 10, 0)
        val sched = schedule(activeDays = listOf(1, 2, 3, 4, 5), startMin = 9 * 60, endMin = 18 * 60)
        assertFalse(evaluator.isScheduleActive(sched, now))
    }

    // ── resolveSchedule ───────────────────────────────────────────────────────

    @Test
    fun `resolveSchedule returns null when inheritSchedule is false and no scheduleId`() {
        val task = fakeTask(inheritSchedule = false, scheduleId = null)
        val result = evaluator.resolveSchedule(task, null)
        assertTrue(result == null)
    }

    @Test
    fun `resolveSchedule returns null when inheritSchedule is true but no group schedule`() {
        val task = fakeTask(inheritSchedule = true, scheduleId = null)
        val result = evaluator.resolveSchedule(task, null)
        assertTrue(result == null)
    }

    private fun fakeTask(inheritSchedule: Boolean, scheduleId: String?) = Task(
        id = "t1", todoId = "todo1", title = "T",
        status = TaskStatus.PENDING, priority = 2,
        dueDate = 0L, startTime = null, reminderAt = null,
        locationId = null, scheduleId = scheduleId,
        inheritSchedule = inheritSchedule,
        recurrenceId = null, recurrenceInstanceDate = null,
        parentTaskId = null, scoreCache = 0f,
        createdAt = 0L, updatedAt = 0L, deletedAt = null,
    )
}

package com.example.todoit.domain.engine

import com.example.todoit.domain.model.Location
import com.example.todoit.domain.model.Schedule
import com.example.todoit.domain.model.Task
import com.example.todoit.domain.model.TaskStatus
import org.junit.Assert.assertEquals
import org.junit.Assert.assertTrue
import org.junit.Before
import org.junit.Test

class TaskScorerTest {

    private lateinit var scheduleEvaluator: ScheduleEvaluator
    private lateinit var scorer: TaskScorer

    // A fixed "now" so tests are deterministic: 2025-01-15 10:00 UTC (Wednesday)
    private val NOW = 1_736_935_200_000L // 2025-01-15T10:00:00Z

    @Before
    fun setUp() {
        scheduleEvaluator = ScheduleEvaluator()
        scorer = TaskScorer(scheduleEvaluator)
    }

    // ── Helper ─────────────────────────────────────────────────────────────────
    private fun task(
        status: TaskStatus = TaskStatus.PENDING,
        priority: Int = 3,
        dueDate: Long = NOW + 100 * 3_600_000L,  // 100h > 72h → 0 due-date pts
        locationId: String? = null,
    ) = Task(
        id = "t1", todoId = "todo1", title = "Test",
        status = status, priority = priority, dueDate = dueDate,
        startTime = null, reminderAt = null, locationId = locationId,
        scheduleId = null, inheritSchedule = false, recurrenceId = null,
        recurrenceInstanceDate = null, parentTaskId = null, scoreCache = 0f,
        createdAt = NOW, updatedAt = NOW, deletedAt = null,
    )

    private fun location(lat: Double, lng: Double, radius: Float = 500f) = Location(
        id = "loc1", label = "Office",
        latitude = lat, longitude = lng,
        radiusMeters = radius,
        updatedAt = NOW, deletedAt = null,
    )

    // ── Priority tests ─────────────────────────────────────────────────────────

    @Test
    fun `priority 1 gives 40 pts base`() {
        val score = scorer.score(task(priority = 1), null, null, null, now = NOW)
        assertEquals(40f, score, 0.01f)
    }

    @Test
    fun `priority 2 gives 30 pts base`() {
        val score = scorer.score(task(priority = 2), null, null, null, now = NOW)
        assertEquals(30f, score, 0.01f)
    }

    @Test
    fun `priority 3 gives 20 pts base`() {
        val score = scorer.score(task(priority = 3), null, null, null, now = NOW)
        assertEquals(20f, score, 0.01f)
    }

    @Test
    fun `priority 4 gives 10 pts base`() {
        val score = scorer.score(task(priority = 4), null, null, null, now = NOW)
        assertEquals(10f, score, 0.01f)
    }

    // ── Due date tests ─────────────────────────────────────────────────────────

    @Test
    fun `overdue task adds 30 pts`() {
        val overdue = task(dueDate = NOW - 1_000)
        val score = scorer.score(overdue, null, null, null, now = NOW)
        // priority 3 (20) + overdue (30) = 50
        assertEquals(50f, score, 0.01f)
    }

    @Test
    fun `due within 2h adds 20 pts`() {
        val due2h = task(dueDate = NOW + 1 * 3_600_000L)
        val score = scorer.score(due2h, null, null, null, now = NOW)
        // priority 3 (20) + due≤2h (20) = 40
        assertEquals(40f, score, 0.01f)
    }

    @Test
    fun `due within 24h adds 10 pts`() {
        val due24h = task(dueDate = NOW + 12 * 3_600_000L)
        val score = scorer.score(due24h, null, null, null, now = NOW)
        // priority 3 (20) + due≤24h (10) = 30
        assertEquals(30f, score, 0.01f)
    }

    @Test
    fun `due within 72h adds 5 pts`() {
        val due72h = task(dueDate = NOW + 50 * 3_600_000L)
        val score = scorer.score(due72h, null, null, null, now = NOW)
        // priority 3 (20) + due≤72h (5) = 25
        assertEquals(25f, score, 0.01f)
    }

    @Test
    fun `due beyond 72h adds 0 pts`() {
        val farFuture = task(dueDate = NOW + 100 * 3_600_000L) // default is already 100h
        val score = scorer.score(farFuture, null, null, null, now = NOW)
        assertEquals(20f, score, 0.01f) // only priority 3 pts
    }

    // ── Status exclusion ───────────────────────────────────────────────────────

    @Test
    fun `DONE tasks return -1`() {
        val score = scorer.score(task(status = TaskStatus.DONE), null, null, null, now = NOW)
        assertEquals(-1f, score, 0.01f)
    }

    // ── Schedule exclusion ─────────────────────────────────────────────────────

    @Test
    fun `schedule inactive returns -1`() {
        // NOW is Wednesday (day 3), schedule only allows Mon (1) and Tue (2)
        val schedule = Schedule("s1", "Weekdays", activeDays = listOf(1, 2),
            startTimeOfDay = null, endTimeOfDay = null, updatedAt = NOW, deletedAt = null)
        val score = scorer.score(task(), null, null, null, schedule, NOW)
        assertEquals(-1f, score, 0.01f)
    }

    @Test
    fun `schedule active returns positive score`() {
        // NOW is Wednesday (day 3), schedule allows Wednesday (3)
        val schedule = Schedule("s1", "Wed", activeDays = listOf(3),
            startTimeOfDay = null, endTimeOfDay = null, updatedAt = NOW, deletedAt = null)
        val score = scorer.score(task(), null, null, null, schedule, NOW)
        assertTrue(score > 0f)
    }

    // ── Location proximity ─────────────────────────────────────────────────────

    @Test
    fun `within radius adds 20 pts`() {
        // User at (0,0), task at (0,0.001) — ~111m apart, radius 500m
        val loc = location(lat = 0.0, lng = 0.001, radius = 500f)
        val score = scorer.score(task(locationId = "loc1"), loc, 0.0, 0.0, now = NOW)
        // priority 3 (20) + within radius (20) + 48h-future (0) = 40
        assertEquals(40f, score, 0.01f)
    }

    @Test
    fun `within 2x radius adds 10 pts`() {
        // User at (0,0), task at (0,0.006) — ~668m, radius = 500m → 668 > 500 but < 1000
        val loc = location(lat = 0.0, lng = 0.006, radius = 500f)
        val score = scorer.score(task(locationId = "loc1"), loc, 0.0, 0.0, now = NOW)
        // priority 3 (20) + 2x radius (10) = 30
        assertEquals(30f, score, 0.01f)
    }

    @Test
    fun `outside 2x radius adds 0 pts`() {
        // User at (0,0), task location far away
        val loc = location(lat = 10.0, lng = 10.0, radius = 500f)
        val score = scorer.score(task(locationId = "loc1"), loc, 0.0, 0.0, now = NOW)
        assertEquals(20f, score, 0.01f) // only priority pts
    }

    @Test
    fun `no location data adds 0 pts`() {
        val score = scorer.score(task(), null, null, null, now = NOW)
        assertEquals(20f, score, 0.01f)
    }

    // ── Haversine ──────────────────────────────────────────────────────────────

    @Test
    fun `haversine distance between same points is 0`() {
        val dist = scorer.haversineDistance(48.8566, 2.3522, 48.8566, 2.3522)
        assertEquals(0.0, dist, 0.01)
    }

    @Test
    fun `haversine distance Paris to London is approx 343 km`() {
        // Paris: 48.8566° N, 2.3522° E
        // London: 51.5074° N, -0.1278° W
        val dist = scorer.haversineDistance(48.8566, 2.3522, 51.5074, -0.1278)
        assertTrue("Expected ~340km, got ${dist / 1000}km", dist in 335_000.0..350_000.0)
    }
}

package com.example.todoit.domain.usecase.group

import com.example.todoit.domain.model.Group
import com.example.todoit.domain.model.GroupNode
import com.example.todoit.domain.repository.GroupRepository
import io.mockk.coEvery
import io.mockk.mockk
import kotlinx.coroutines.flow.flowOf
import kotlinx.coroutines.test.runTest
import org.junit.Assert.assertEquals
import org.junit.Assert.assertTrue
import org.junit.Before
import org.junit.Test

class GetGroupTreeUseCaseTest {

    private lateinit var repository: GroupRepository
    private lateinit var useCase: GetGroupTreeUseCase

    private val NOW = System.currentTimeMillis()

    @Before
    fun setUp() {
        repository = mockk()
        useCase = GetGroupTreeUseCase(repository)
    }

    // ── Helper ─────────────────────────────────────────────────────────────────

    private fun group(id: String, parentId: String? = null, deleted: Boolean = false) = Group(
        id = id, parentId = parentId, name = "Group $id",
        color = null, scheduleId = null,
        createdAt = NOW, updatedAt = NOW,
        deletedAt = if (deleted) NOW else null,
    )

    // ── getOnce tests ─────────────────────────────────────────────────────────

    @Test
    fun `empty group list returns empty tree`() = runTest {
        coEvery { repository.getAllGroups() } returns emptyList()
        val tree = useCase.getOnce()
        assertTrue(tree.isEmpty())
    }

    @Test
    fun `flat groups with no parent build single-level tree`() = runTest {
        val groups = listOf(group("a"), group("b"), group("c"))
        coEvery { repository.getAllGroups() } returns groups
        val tree = useCase.getOnce()
        assertEquals(3, tree.size)
        assertTrue(tree.all { it.children.isEmpty() })
    }

    @Test
    fun `child is nested under its parent`() = runTest {
        val parent = group("parent")
        val child  = group("child", parentId = "parent")
        coEvery { repository.getAllGroups() } returns listOf(parent, child)

        val tree = useCase.getOnce()

        assertEquals(1, tree.size)                        // only one root
        assertEquals("parent", tree[0].group.id)
        assertEquals(1, tree[0].children.size)            // one child
        assertEquals("child", tree[0].children[0].group.id)
    }

    @Test
    fun `3-level nesting builds correctly`() = runTest {
        val root       = group("root")
        val mid        = group("mid", parentId = "root")
        val leaf       = group("leaf", parentId = "mid")
        coEvery { repository.getAllGroups() } returns listOf(root, mid, leaf)

        val tree = useCase.getOnce()

        assertEquals(1, tree.size)
        val midNode = tree[0].children.single()
        assertEquals("mid", midNode.group.id)
        val leafNode = midNode.children.single()
        assertEquals("leaf", leafNode.group.id)
        assertTrue(leafNode.children.isEmpty())
    }

    @Test
    fun `deleted groups are excluded`() = runTest {
        val active  = group("active")
        val deleted = group("deleted", deleted = true)
        coEvery { repository.getAllGroups() } returns listOf(active, deleted)

        val tree = useCase.getOnce()

        assertEquals(1, tree.size)
        assertEquals("active", tree[0].group.id)
    }

    @Test
    fun `orphaned child (parent deleted) is excluded`() = runTest {
        // "parent" is deleted → child referencing it becomes orphan
        val parent = group("parent", deleted = true)
        val child  = group("child", parentId = "parent")
        coEvery { repository.getAllGroups() } returns listOf(parent, child)

        val tree = useCase.getOnce()

        // parent is deleted → not in tree
        // child has parentId "parent" → not included at root (its parentId != null)
        // → tree is empty (or just contains the child if orphan handling is relaxed)
        // The current implementation: deleted parent excluded → child's parentId != null so also not root
        assertTrue(tree.isEmpty())
    }

    @Test
    fun `multiple roots each with children`() = runTest {
        val r1  = group("r1")
        val r2  = group("r2")
        val c1  = group("c1", parentId = "r1")
        val c2  = group("c2", parentId = "r1")
        val c3  = group("c3", parentId = "r2")
        coEvery { repository.getAllGroups() } returns listOf(r1, r2, c1, c2, c3)

        val tree = useCase.getOnce()

        assertEquals(2, tree.size)
        val rootR1 = tree.first { it.group.id == "r1" }
        val rootR2 = tree.first { it.group.id == "r2" }
        assertEquals(2, rootR1.children.size)
        assertEquals(1, rootR2.children.size)
    }

    // ── observe (Flow) test ───────────────────────────────────────────────────

    @Test
    fun `observe emits live tree from flow`() = runTest {
        val groups = listOf(group("x"), group("y"))
        coEvery { repository.observeGroups() } returns flowOf(groups)

        val results = mutableListOf<List<GroupNode>>()
        useCase.observe().collect { results.add(it) }

        assertEquals(1, results.size)
        assertEquals(2, results[0].size)
    }
}
